import{_ as o,c as a,o as t,a1 as n}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Google Cloud 配额查询 | opencode-mystatus","description":"学习 Google Cloud 配额查询。查看 G3 Pro、G3 Image、G3 Flash、Claude 的剩余配额和重置时间，管理多账户。","frontmatter":{"title":"Google Cloud 配额查询 | opencode-mystatus","sidebarTitle":"Google Cloud 配额","subtitle":"Google Cloud 配额查询：查看 G3 Pro/Image/Flash 和 Claude","description":"学习 Google Cloud 配额查询。查看 G3 Pro、G3 Image、G3 Flash、Claude 的剩余配额和重置时间，管理多账户。","tags":["Google Cloud","Antigravity","Quota Query"],"prerequisite":["start-quick-start","start-using-mystatus"],"order":999},"headers":[],"relativePath":"vbgate/opencode-mystatus/platforms/google-usage/index.md","filePath":"vbgate/opencode-mystatus/platforms/google-usage/index.md"}'),l={name:"vbgate/opencode-mystatus/platforms/google-usage/index.md"};function s(i,e,r,d,u,c){return t(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="google-cloud-quota-check-g3-pro-image-flash-and-claude" tabindex="-1">Google Cloud Quota Check: G3 Pro/Image/Flash and Claude <a class="header-anchor" href="#google-cloud-quota-check-g3-pro-image-flash-and-claude" aria-label="Permalink to &quot;Google Cloud Quota Check: G3 Pro/Image/Flash and Claude&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>View quotas for 4 models on Google Cloud Antigravity accounts</li><li>Understand reset time and remaining percentage for each model</li><li>Manage quota usage across multiple Google Cloud accounts</li></ul><h2 id="your-current-pain-point" tabindex="-1">Your Current Pain Point <a class="header-anchor" href="#your-current-pain-point" aria-label="Permalink to &quot;Your Current Pain Point&quot;">​</a></h2><p>Google Cloud Antigravity provides multiple models (G3 Pro, G3 Image, G3 Flash, Claude), each with independent quotas and reset times. You need to:</p><ul><li>Log into Google Cloud Console separately to check each model&#39;s status</li><li>Manually calculate remaining quotas and reset times</li><li>It&#39;s even more chaotic when managing multiple accounts</li></ul><h2 id="when-to-use-this" tabindex="-1">When to Use This <a class="header-anchor" href="#when-to-use-this" aria-label="Permalink to &quot;When to Use This&quot;">​</a></h2><p>When you:</p><ul><li>Want to quickly check remaining quotas for all Google Cloud models</li><li>Need to plan usage allocation across different models</li><li>Have multiple Google Cloud accounts to manage uniformly</li></ul><h2 id="🎒-prerequisites" tabindex="-1">🎒 Prerequisites <a class="header-anchor" href="#🎒-prerequisites" aria-label="Permalink to &quot;🎒 Prerequisites&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Prerequisites Check</p><ol><li><strong>mystatus plugin installed</strong>: Refer to <a href="/docs/opencodedocs/vbgate/opencode-mystatus/start/quick-start/">Quick Start</a></li><li><strong>Google Cloud authentication configured</strong>: First install <a href="https://github.com/NoeFabris/opencode-antigravity-auth" target="_blank" rel="noreferrer">opencode-antigravity-auth</a> plugin to complete OAuth authentication</li><li><strong>Authentication file exists</strong>: <code>~/.config/opencode/antigravity-accounts.json</code> contains at least one account</li></ol></div><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p>Google Cloud Antigravity authenticates via OAuth mechanism, with each account having an independent Refresh Token. The mystatus plugin will:</p><ol><li>Read <code>antigravity-accounts.json</code> to get all configured accounts</li><li>Use Refresh Token to refresh Access Token</li><li>Call Google Cloud API to get quotas for all models</li><li>Display quotas and reset times for 4 models, grouped by account</li></ol><h2 id="google-cloud-supported-models" tabindex="-1">Google Cloud Supported Models <a class="header-anchor" href="#google-cloud-supported-models" aria-label="Permalink to &quot;Google Cloud Supported Models&quot;">​</a></h2><p>mystatus displays quotas for the following 4 models:</p><table tabindex="0"><thead><tr><th>Display Name</th><th>Model Key (Primary/Backup)</th><th>Description</th></tr></thead><tbody><tr><td>G3 Pro</td><td><code>gemini-3-pro-high</code> / <code>gemini-3-pro-low</code></td><td>Gemini 3 Pro high-performance version</td></tr><tr><td>G3 Image</td><td><code>gemini-3-pro-image</code></td><td>Gemini 3 Pro image generation</td></tr><tr><td>G3 Flash</td><td><code>gemini-3-flash</code></td><td>Gemini 3 Flash fast version</td></tr><tr><td>Claude</td><td><code>claude-opus-4-5-thinking</code> / <code>claude-opus-4-5</code></td><td>Claude Opus 4.5 model</td></tr></tbody></table><p><strong>Primary Key and Backup Key Mechanism</strong>:</p><ul><li>API response may return data for only primary key or backup key</li><li>mystatus automatically attempts to fetch quota for either key</li><li>For example: if <code>gemini-3-pro-high</code> has no data, it will try <code>gemini-3-pro-low</code></li></ul><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-execute-query-command" tabindex="-1">Step 1: Execute Query Command <a class="header-anchor" href="#step-1-execute-query-command" aria-label="Permalink to &quot;Step 1: Execute Query Command&quot;">​</a></h3><p><strong>Why</strong> Quickly get quota information for all Google Cloud accounts</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mystatus</span></span></code></pre></div><p><strong>You Should See</strong> Quota information for all configured platforms, where the Google Cloud section will show content similar to:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Google Cloud Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Image   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Flash   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>Claude     2d 9h      ░░░░░░░░░░░░░░░░░░░░ 0%</span></span></code></pre></div><h3 id="step-2-understand-output-format" tabindex="-1">Step 2: Understand Output Format <a class="header-anchor" href="#step-2-understand-output-format" aria-label="Permalink to &quot;Step 2: Understand Output Format&quot;">​</a></h3><p><strong>Why</strong> Quickly locate key information: remaining quota and reset time</p><p>Each line format:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[model name] [reset time] [progress bar] [remaining percentage]</span></span></code></pre></div><p><strong>Field Description</strong>:</p><ul><li><strong>Model name</strong>: G3 Pro, G3 Image, G3 Flash, Claude</li><li><strong>Reset time</strong>: Time remaining until next quota reset (e.g., <code>4h 59m</code>, <code>2d 9h</code>)</li><li><strong>Progress bar</strong>: Visual display of remaining percentage</li><li><strong>Remaining percentage</strong>: Value from 0-100</li></ul><p><strong>You Should See</strong> One line per model, clearly showing quota and reset time</p><h3 id="step-3-view-multiple-accounts" tabindex="-1">Step 3: View Multiple Accounts <a class="header-anchor" href="#step-3-view-multiple-accounts" aria-label="Permalink to &quot;Step 3: View Multiple Accounts&quot;">​</a></h3><p><strong>Why</strong> If you have multiple Google Cloud accounts, they will be displayed separately</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Image   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### another@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     2h 30m     ████████████░░░░░░░░░ 75%</span></span>
<span class="line"><span>G3 Image   2h 30m     ████████████░░░░░░░░░ 75%</span></span></code></pre></div><p><strong>You Should See</strong> Each account in a separate section, containing that account&#39;s 4 model quotas</p><h3 id="step-4-check-quota-warnings" tabindex="-1">Step 4: Check Quota Warnings <a class="header-anchor" href="#step-4-check-quota-warnings" aria-label="Permalink to &quot;Step 4: Check Quota Warnings&quot;">​</a></h3><p><strong>Why</strong> Avoid service interruption due to overuse</p><p>If usage of any model exceeds 80%, a warning prompt will appear:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     1h 30m     ████░░░░░░░░░░░░░░░ 20%</span></span>
<span class="line"><span>G3 Image   1h 30m     ████░░░░░░░░░░░░░░ 20%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>⚠️ Usage has reached or exceeded 80%</span></span></code></pre></div><p><strong>You Should See</strong> Warning prompt appears below the model list for the corresponding account</p><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><p>Complete the following checks to ensure you did it correctly:</p><ul><li>[ ] Can see Google Cloud quota information after running <code>/mystatus</code></li><li>[ ] Can understand the names and reset times for 4 models</li><li>[ ] Can identify progress bars and remaining percentages</li><li>[ ] If multiple accounts exist, can see quotas for all accounts</li></ul><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><h3 id="problem-1-cannot-see-google-cloud-quota" tabindex="-1">Problem 1: Cannot See Google Cloud Quota <a class="header-anchor" href="#problem-1-cannot-see-google-cloud-quota" aria-label="Permalink to &quot;Problem 1: Cannot See Google Cloud Quota&quot;">​</a></h3><p><strong>Possible Causes</strong>:</p><ul><li>opencode-antigravity-auth plugin not installed</li><li>Google OAuth authentication not completed</li><li><code>antigravity-accounts.json</code> file doesn&#39;t exist or is empty</li></ul><p><strong>Solution</strong>:</p><ol><li>Install opencode-antigravity-auth plugin</li><li>Complete authentication following the GitHub repository instructions</li><li>Run <code>/mystatus</code> again</li></ol><h3 id="problem-2-error-displayed-for-an-account" tabindex="-1">Problem 2: Error Displayed for an Account <a class="header-anchor" href="#problem-2-error-displayed-for-an-account" aria-label="Permalink to &quot;Problem 2: Error Displayed for an Account&quot;">​</a></h3><p><strong>Possible Causes</strong>:</p><ul><li>Refresh Token expired</li><li>projectId missing</li></ul><p><strong>Error Example</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>user@gmail.com: No project ID found</span></span></code></pre></div><p><strong>Solution</strong>:</p><ol><li>Re-authenticate that account using opencode-antigravity-auth plugin</li><li>Ensure project ID is correctly set during authentication</li></ol><h3 id="problem-3-model-shows-or-reset-time-abnormal" tabindex="-1">Problem 3: Model Shows &quot;-&quot; or Reset Time Abnormal <a class="header-anchor" href="#problem-3-model-shows-or-reset-time-abnormal" aria-label="Permalink to &quot;Problem 3: Model Shows &quot;-&quot; or Reset Time Abnormal&quot;">​</a></h3><p><strong>Possible Causes</strong>:</p><ul><li>API response resetTime field missing or in wrong format</li><li>No quota information available for that model</li></ul><p><strong>Solution</strong>:</p><ul><li>This is normal, mystatus displays &quot;-&quot; to indicate data unavailable</li><li>If all models show &quot;-&quot;, check network connection or Google Cloud API status</li></ul><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><ul><li>Google Cloud Antigravity supports 4 models: G3 Pro, G3 Image, G3 Flash, Claude</li><li>Each model has independent quotas and reset times</li><li>Supports multi-account management, with each account displayed separately</li><li>Warning prompt appears when usage exceeds 80%</li></ul><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../../advanced/google-setup/">Google Cloud Advanced Configuration: Multi-Account and Model Management</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>How to add and manage multiple Google Cloud accounts</li><li>Understand the mapping relationship for 4 models</li><li>Differences between projectId and managedProjectId</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Function</th><th>File Path</th><th>Line Numbers</th></tr></thead><tbody><tr><td>Model configuration</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L69-L78" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>69-78</td></tr><tr><td>Account query logic</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L304-L370" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>304-370</td></tr><tr><td>Token refresh</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L162-L184" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>162-184</td></tr><tr><td>Quota extraction</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L132-L157" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>132-157</td></tr><tr><td>Format output</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L265-L294" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>265-294</td></tr><tr><td>Type definitions</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/types.ts#L78-L94" target="_blank" rel="noreferrer"><code>plugin/lib/types.ts</code></a></td><td>78-94</td></tr></tbody></table><p><strong>Key Constants</strong>:</p><ul><li><code>GOOGLE_QUOTA_API_URL = &quot;https://cloudcode-pa.googleapis.com/v1internal:fetchAvailableModels&quot;</code>: Google Cloud quota query API</li><li><code>GOOGLE_TOKEN_REFRESH_URL = &quot;https://oauth2.googleapis.com/token&quot;</code>: OAuth Token refresh API</li><li><code>USER_AGENT = &quot;antigravity/1.11.9 windows/amd64&quot;</code>: API request User-Agent</li></ul><p><strong>Key Functions</strong>:</p><ul><li><code>queryGoogleUsage()</code>: Query quotas for all Antigravity accounts</li><li><code>fetchAccountQuota()</code>: Query quota for a single account</li><li><code>extractModelQuotas()</code>: Extract quotas for 4 models from API response</li><li><code>formatAccountQuota()</code>: Format display of single account quota</li></ul><p><strong>Model Mapping Rules</strong>:</p><ul><li>G3 Pro supports <code>gemini-3-pro-high</code> and <code>gemini-3-pro-low</code>, prioritizing primary key</li><li>Claude supports <code>claude-opus-4-5-thinking</code> and <code>claude-opus-4-5</code>, prioritizing primary key</li><li>G3 Image and G3 Flash have only one key</li></ul></details>`,69)])])}const h=o(l,[["render",s]]);export{g as __pageData,h as default};
